local OOO000O0O='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function OO000000O(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..OOO000O0O..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(OOO000O0O:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local OOOO0000O=OO000000O(OOO0OO0O0)
